const MID_OPACITY = 0.34;
const HIGH_OPACITY = 0.95;
/** Discrete checker frames per loop (must stay integer for `(row + col + t) % 2`). */
const CHECKER_STEPS = 4;

export function CellOrbit17({
  speed = 1,
  animated = true,
  hoverAnimated = false,
  ...rest
