function isWithinTriangleMask(row: number, col: number): boolean {
  if (row < 0 || row >= MATRIX_SIZE || col < 0 || col >= MATRIX_SIZE) {
    return false;
  }

  // Staggered 1-2-3-4 triangle (base has exactly 4 cells), matching reference silhouette.
